insert into public.contract_records (
  company_id, company_name, contract_name, contract_date, contract_year, contract_amount, buyer, product_category, source_id, raw
)
select
  rows.company_id, rows.company_name, rows.contract_name, rows.contract_date::date, rows.contract_year, rows.contract_amount, rows.buyer, rows.product_category, s.id, rows.raw
from rows
left join public.company_sources s
  on s.company_id = rows.company_id
  and s.source_type = 'domestic_procurement_contract_summary'
where not exists (
  select 1
  from public.contract_records existing
  where existing.company_id = rows.company_id
    and existing.raw->>'contract_number' = rows.raw->>'contract_number'
    and existing.raw->>'contract_sequence' = rows.raw->>'contract_sequence'
);
